from flask import Flask, jsonify
from flask_graphql import GraphQLView
import graphene


PRODUCTS = [
    {"id": "1", "name": "Laptop Pro 15", "description": "High-performance laptop", "price": 1499.99, "category_id": "1"},
    {"id": "2", "name": "Wireless Mouse", "description": "Ergonomic Bluetooth mouse", "price": 39.99, "category_id": "2"},
    {"id": "3", "name": "Mechanical Keyboard", "description": "RGB backlit keyboard", "price": 89.99, "category_id": "2"},
    {"id": "4", "name": "Noise Cancelling Headphones", "description": "Over-ear wireless headphones", "price": 249.99, "category_id": "3"},
]

CATEGORIES = [
    {"id": "1", "name": "Computers"},
    {"id": "2", "name": "Accessories"},
    {"id": "3", "name": "Audio"},
]

REVIEWS = [
    {"id": "1", "product_id": "1", "user_name": "Alice", "rating": 5, "comment": "Excellent laptop for work and gaming."},
    {"id": "2", "product_id": "1", "user_name": "Bob", "rating": 4, "comment": "Great performance but battery life could be better."},
    {"id": "3", "product_id": "2", "user_name": "Charlie", "rating": 5, "comment": "Very comfortable and responsive mouse."},
    {"id": "4", "product_id": "4", "user_name": "Dana", "rating": 4, "comment": "Sound quality is amazing."},
]


class Category(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    products = graphene.List(lambda: Product)

    def resolve_products(parent, info):
        return [p for p in PRODUCTS if p["category_id"] == parent["id"]]


class Review(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_name = graphene.String(required=True)
    rating = graphene.Int(required=True)
    comment = graphene.String(required=True)
    product = graphene.Field(lambda: Product)

    def resolve_product(parent, info):
        return next((p for p in PRODUCTS if p["id"] == parent["product_id"]), None)


class Product(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String(required=True)
    price = graphene.Float(required=True)
    category_id = graphene.ID(required=True)
    category = graphene.Field(Category)
    reviews = graphene.List(Review)

    def resolve_category(parent, info):
        return next((c for c in CATEGORIES if c["id"] == parent["category_id"]), None)

    def resolve_reviews(parent, info):
        return [r for r in REVIEWS if r["product_id"] == parent["id"]]


class Query(graphene.ObjectType):
    products = graphene.List(Product, category_id=graphene.ID(), min_price=graphene.Float(), max_price=graphene.Float())
    product = graphene.Field(Product, id=graphene.ID(required=True))
    categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    reviews = graphene.List(Review, product_id=graphene.ID())
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(root, info, category_id=None, min_price=None, max_price=None):
        results = PRODUCTS[:]
        if category_id is not None:
            results = [p for p in results if p["category_id"] == category_id]
        if min_price is not None:
            results = [p for p in results if p["price"] >= min_price]
        if max_price is not None:
            results = [p for p in results if p["price"] <= max_price]
        return results

    def resolve_product(root, info, id):
        return next((p for p in PRODUCTS if p["id"] == id), None)

    def resolve_categories(root, info):
        return CATEGORIES

    def resolve_category(root, info, id):
        return next((c for c in CATEGORIES if c["id"] == id), None)

    def resolve_reviews(root, info, product_id=None):
        if product_id is None:
            return REVIEWS
        return [r for r in REVIEWS if r["product_id"] == product_id]

    def resolve_review(root, info, id):
        return next((r for r in REVIEWS if r["id"] == id), None)


schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,
    ),
)


@app.route("/")
def index():
    return jsonify(
        {
            "service": "e-commerce-product-catalog-api",
            "graphql_endpoint": "/graphql",
            "graphiql": True,
            "introspection": "enabled",
        }
    )


if __name__ == "__main__":
    app.run(debug=True)